// Готовим по одному пакету данных на каждого worker-а:
// — список всех задач этого worker-а (отсортирован по queued_at)
// — отдельно queued и active задачи с их количеством (для numeric-условий в IF-нодах)
// — все endpoint-ы OpenCode из routing-конфигурации
// — модель OpenCode (разбираем из формата "provider/model", например "deepseek/deepseek-v4-pro")

const routing = $('Задаём конфигурацию OpenCode').first().json
const allTasks = $('Получаем все задачи').all().map((item) => item.json)

// Сортировка задач: более ранние (queued_at меньше) — выше
function sortByQueuedAt(left, right) {
  return String(left.queued_at || '').localeCompare(String(right.queued_at || ''))
}

// Разбор строки "provider/model" → { providerID, modelID }
// Возвращает null если формат невалидный (пусто, нет /, / в начале или конце)
function parseModel(modelRef) {
  const normalized = String(modelRef || '').trim()
  const separatorIndex = normalized.indexOf('/')

  if (!normalized || separatorIndex <= 0 || separatorIndex === normalized.length - 1) {
    return null
  }

  return {
    providerID: normalized.slice(0, separatorIndex),
    modelID: normalized.slice(separatorIndex + 1),
  }
}

return Object.entries(routing.workers || {})
  // Сортируем по давности очереди: воркеры с самой старой задачей — первые
  .sort((a, b) => {
    const aTasks = allTasks.filter(t => String(t.worker_alias || '').trim() === a[0]).sort(sortByQueuedAt)
    const bTasks = allTasks.filter(t => String(t.worker_alias || '').trim() === b[0]).sort(sortByQueuedAt)
    const aOldest = aTasks.filter(t => String(t.status || '').trim() === 'queued')[0]
    const bOldest = bTasks.filter(t => String(t.status || '').trim() === 'queued')[0]
    if (!aOldest && !bOldest) return 0
    if (!aOldest) return 1
    if (!bOldest) return -1
    return String(aOldest.queued_at || '').localeCompare(String(bOldest.queued_at || ''))
  })
  .map(([workerAlias, workerConfig]) => {
  const workerTasks = allTasks
    .filter((task) => String(task.worker_alias || '').trim() === workerAlias)
    .sort(sortByQueuedAt)

  const queuedTasks = workerTasks.filter((task) => String(task.status || '').trim() === 'queued')
  const activeTasks = workerTasks.filter((task) =>
    ['running', 'needs_input'].includes(String(task.status || '').trim())
  )

  return {
    pairedItem: 0,
    json: {
      workerAlias,
      workerBaseUrl: String(workerConfig.baseUrl || '').trim(),
      authorizationHeader: String(workerConfig.authorizationHeader || '').trim(),
      sessionCreatePath: String(routing.endpoints?.sessionCreate || '').trim(),
      messageListPath: String(routing.endpoints?.messageList || '').trim(),
      questionListPath: String(routing.endpoints?.questionList || '').trim(),
      questionReplyPath: String(routing.endpoints?.questionReply || '').trim(),
      questionRejectPath: String(routing.endpoints?.questionReject || '').trim(),
      permissionListPath: String(routing.endpoints?.permissionList || '').trim(),
      permissionReplyPath: String(routing.endpoints?.permissionReply || '').trim(),
      sessionStatusPath: String(routing.endpoints?.sessionStatus || '').trim(),
      promptAsyncPath: String(routing.endpoints?.promptAsync || '').trim(),
      opencodeAgent: String(routing.defaultAgent || 'build').trim(),
      opencodeModel: parseModel(routing.defaultModel),
      opencodeVariant: String(workerConfig.variant || routing.defaultVariant || '').trim(),
      workerTasks,
      queuedTasks,
      queuedTasksCount: queuedTasks.length,
      activeTasks,
      activeTasksCount: activeTasks.length,
    },
  }
})

// Берём пакет данных текущего worker-а, который уже содержит только queued задачи
// и количество активных задач этого worker-а.
const workerPackage = $('Готовим пакеты обработчиков').item.json
const queuedTasks = (Array.isArray(workerPackage.queuedTasks) ? workerPackage.queuedTasks : []).filter((task) => {
  // Не берём задачи, запланированные на будущее (повторы с --interval)
  const queuedAt = String(task.queued_at || '').trim()
  if (!queuedAt) return true
  return new Date(queuedAt) <= new Date()
})
const workerTasks = Array.isArray(workerPackage.workerTasks) ? workerPackage.workerTasks : []

// Приоритет всегда у зависимых задач.
// Если зависимых задач нет, берём самую раннюю обычную queued-задачу.
// Зависимые задачи — только если родитель УЖЕ не в очереди (запущен/завершён)
const dependentTasks = queuedTasks.filter((task) => {
  const parentKey = String(task.parent_task_key || '').trim()
  if (!parentKey) return false
  return !queuedTasks.some((t) => String(t.task_key || '').trim() === parentKey)
})
const regularTasks = queuedTasks.filter((task) => !String(task.parent_task_key || '').trim())
const selectedTask = dependentTasks[0] || regularTasks[0] || null

let context = {}
try {
  context = JSON.parse(String(selectedTask?.context_json || '{}'))
} catch {
  context = {}
}

const chatId = String(selectedTask?.chat_id || '').trim()
const sessionHistory = workerTasks
  .filter((task) => String(task.chat_id || '').trim() === chatId)
  .filter((task) => String(task.session_id || '').trim())
  .filter((task) => ['running', 'needs_input', 'done'].includes(String(task.status || '').trim()))

const latestSessionTask = sessionHistory[sessionHistory.length - 1] || null
const historySessionId = String(latestSessionTask?.session_id || '').trim()
const taskPresetSessionId = String(selectedTask?.session_id || '').trim()
const latestSessionId = taskPresetSessionId || historySessionId
const newSessionRequested = Boolean(
  context.newSessionRequested ||
  context.flags?.['new-session'] ||
  context.flags?.['new_session'] ||
  context.flags?.['fresh-session'] ||
  context.flags?.['fresh_session']
)

return {
  json: {
    task: selectedTask,
    parentTaskKey: String(selectedTask?.parent_task_key || '').trim(),
    parentMatchText: String(selectedTask?.parent_match_text || '').trim(),
    promptText: String(selectedTask?.prompt || '').trim(),
    latestSessionId,
    createNewSession: newSessionRequested || !latestSessionId,
    acceptanceCriteria: String(context.acceptanceCriteria || '').trim(),
    originalPrompt: String(context.originalPrompt || selectedTask?.prompt || '').trim(),
  },
}

// Выбираем первую активную задачу для текущего worker-а.
// Из её context_json извлекаем:
//   abortRequested — пользователь запросил прерывание
//   latestSentId   — id последнего отправленного в Telegram сообщения (для дельты)

const workerPackage = $('Готовим пакеты обработчиков').item.json
const activeTasks = Array.isArray(workerPackage.activeTasks) ? workerPackage.activeTasks : []
const selectedTask = activeTasks[0] || null

let contextJson = {}
let abortRequested = false
let latestSentId = ''
if (selectedTask) {
  try {
    contextJson = JSON.parse(String(selectedTask.context_json || '{}'))
  } catch {}
  abortRequested = contextJson.abortRequested === true
  latestSentId = String(contextJson.latestSentId || '').trim()
}

return {
  json: {
    task: selectedTask,
    taskStatus: String(selectedTask?.status || '').trim(),
    sessionId: String(selectedTask?.session_id || '').trim(),
    pendingQuestion: String(selectedTask?.pending_question || '').trim(),
    pendingOptionsJson: String(selectedTask?.pending_options_json || '[]'),
    abortRequested,
    contextJson,
    latestSentId,
    acceptanceCriteria: String(contextJson.acceptanceCriteria || '').trim(),
    originalPrompt: String(contextJson.originalPrompt || '').trim(),
  },
}

// Копируем sessionId и launchError от менеджера сессий в отдельные поля,
// чтобы exec-launch мог ссылаться на них без проблем paired-item цепочки.

const sessionOutput = $('Управление сессией').first().json

return {
  json: {
    sessionId: String(sessionOutput.sessionId || '').trim(),
    launchError: String(sessionOutput.launchError || '').trim(),
  },
}

// Проверяем нужно ли перезапустить задачу по интервалу
const tasks = $input.all()
const results = []

for (const item of tasks) {
  let context = {}
  try { context = JSON.parse(String(item.json.context_json || '{}')) } catch(e) {}

  // Не повторяем отменённые/прерванные задачи
  const taskStatus = String(item.json.status || '').trim()
  if (taskStatus === 'aborted' || taskStatus === 'cancelled') {
    results.push({ json: { ...item.json, repeatActive: false } })
    continue
  }
  const interval = String(context.repeatInterval || '').trim()
  if (!interval) {
    results.push({ json: { ...item.json, repeatActive: false } })
    continue
  }

  // Парсим интервал: 30m, 4h, 1d
  const match = interval.match(/^(\d+)([mhd])$/)
  if (!match) {
    results.push({ json: { ...item.json, repeatActive: false } })
    continue
  }
  const value = parseInt(match[1])
  const unit = match[2]
  const ms = unit === 'm' ? value * 60000 : unit === 'h' ? value * 3600000 : value * 86400000
  const nextRun = new Date(Date.now() + ms).toISOString()

  results.push({
    json: {
      ...item.json,
      repeatActive: true,
      repeatInterval: interval,
      newQueuedAt: nextRun,
      shouldReset: true,
      replyText: (item.json.replyText || '') + `

🔄 Повтор через ${interval} (${nextRun})`
    }
  })
}

return results
